class Solution {
public:
    vector<int> singleNumber(vector<int>& nums) {
        long long xorAll = 0;
        for (int x : nums) xorAll ^= x;
        long long bit = xorAll & -xorAll;
        int a = 0, b = 0;
        for (int x : nums)
            (x & bit) ? a ^= x : b ^= x;
        return {a, b};
    }
};

